package com.chaobo.scm.supplier.application.operations;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.integration.InboundEventPayloadStore;import com.chaobo.scm.supplier.application.masterdata.MasterDataEventConsumeLogPort;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class OperationsEventConsumerApplicationService{private static final String CONSUMER="supplier-operations";private final MasterDataEventConsumeLogPort inbox;private final SupplierOperationsApplicationService operations;private final InboundEventPayloadStore payloads;public OperationsEventConsumerApplicationService(MasterDataEventConsumeLogPort inbox,SupplierOperationsApplicationService operations,InboundEventPayloadStore payloads){this.inbox=inbox;this.operations=operations;this.payloads=payloads;}@Transactional public void consume(OperationsEvent event){var claim=inbox.claim(event.sourceSystem(),event.eventCode(),event.eventType(),CONSUMER,event.sourceSystem()+":"+event.eventCode());if(claim==MasterDataEventConsumeLogPort.ClaimResult.ALREADY_SUCCEEDED)return;if(claim==MasterDataEventConsumeLogPort.ClaimResult.IN_PROGRESS)throw new BusinessException(ErrorCode.IDEMPOTENCY_CONFLICT,"运营事件正在处理");payloads.save(event.sourceSystem(),event.eventCode(),CONSUMER,event);try{operations.accept(event);inbox.markSucceeded(event.sourceSystem(),event.eventCode(),CONSUMER,false);}catch(RuntimeException exception){inbox.recordFailure(event.sourceSystem(),event.eventCode(),event.eventType(),CONSUMER,event.sourceSystem()+":"+event.eventCode(),exception.getMessage());throw exception;}}}
